// Parse incoming params from the toolWorkflow caller.
// LLM may pass them as a JSON string in `query`, or as direct fields.
const raw = $input.first().json;
let action = '', task = '', url = '', domain = '', maxSteps = 25, timeoutS = 300;
try {
  const p = JSON.parse(raw.query || '{}');
  action = p.action || '';
  task = p.task || '';
  url = p.url || '';
  domain = p.domain || '';
  maxSteps = Number(p.max_steps) || 25;
  timeoutS = Number(p.timeout_s) || 300;
} catch(e) {
  action = raw.action || '';
  task = raw.task || '';
  url = raw.url || '';
  domain = raw.domain || '';
  maxSteps = Number(raw.max_steps) || 25;
  timeoutS = Number(raw.timeout_s) || 300;
}

const userId = raw.userId || raw.user_id || 'telegram:{{TELEGRAM_CHAT_ID}}';
const BRIDGE = 'http://browser-bridge:3400';

function errorResponse(msg) {
  return [{ json: { success: false, error: msg } }];
}

if (!action) {
  return errorResponse('Parameter "action" is required. One of: task, list_sessions, close_session.');
}

if (action === 'task') {
  if (!task) return errorResponse('Parameter "task" is required for action=task.');
  try {
    const res = await helpers.httpRequest({
      method: 'POST',
      url: `${BRIDGE}/tasks`,
      headers: { 'Content-Type': 'application/json' },
      body: {
        user_id: userId,
        task,
        url: url || null,
        domain: domain || null,
        max_steps: maxSteps,
        timeout_s: timeoutS,
      },
      json: true,
      timeout: (timeoutS + 30) * 1000,
    });
    return [{ json: { success: res.status === 'completed', ...res } }];
  } catch(e) {
    return errorResponse(`Browser task failed: ${e.message}`);
  }
}

if (action === 'list_sessions') {
  try {
    const res = await helpers.httpRequest({
      method: 'GET',
      url: `${BRIDGE}/sessions/${encodeURIComponent(userId)}`,
      json: true,
      timeout: 10000,
    });
    const sessions = res.sessions || [];
    if (sessions.length === 0) {
      return [{ json: { success: true, sessions: [], message: 'No active browser sessions.' } }];
    }
    const lines = sessions.map(s => {
      const ageMin = Math.round((Date.now() / 1000 - s.last_used_at) / 60);
      return `- ${s.domain} (idle ${ageMin}m, ${s.n_tasks} tasks)`;
    });
    return [{ json: { success: true, sessions, message: `Active browser sessions:\n${lines.join('\n')}` } }];
  } catch(e) {
    return errorResponse(`Could not list sessions: ${e.message}`);
  }
}

if (action === 'close_session') {
  if (!domain) return errorResponse('Parameter "domain" is required for action=close_session.');
  try {
    const res = await helpers.httpRequest({
      method: 'DELETE',
      url: `${BRIDGE}/sessions/${encodeURIComponent(userId)}/${encodeURIComponent(domain)}`,
      json: true,
      timeout: 10000,
    });
    return [{ json: { success: true, ...res, message: `Browser session for ${domain} closed.` } }];
  } catch(e) {
    if (e.message && e.message.includes('404')) {
      return errorResponse(`No active session for domain "${domain}".`);
    }
    return errorResponse(`Could not close session: ${e.message}`);
  }
}

return errorResponse(`Unknown action "${action}". Use: task, list_sessions, close_session.`);
